using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

[McpServerToolType]
public class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_forecast"), Description("Get the weather forecast for a location.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetFromJsonAsync<ForecastResponse>(
            $"/v1/forecast?latitude={latitude}&longitude={longitude}" +
            "&current=temperature_2m,wind_speed_10m&temperature_unit=celsius");

        if (response?.Current is null)
            return "No forecast data available.";

        return $"Temperature: {response.Current.Temperature}°C, " +
               $"Wind: {response.Current.WindSpeed} km/h";
    }

    [McpServerTool(Name = "get_temperature"), Description("Get just the current temperature for a location.")]
    public async Task<string> GetTemperature(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var response = await client.GetFromJsonAsync<ForecastResponse>(
            $"/v1/forecast?latitude={latitude}&longitude={longitude}" +
            "&current=temperature_2m&temperature_unit=celsius");

        if (response?.Current is null)
            return "No temperature data available.";

        return $"{response.Current.Temperature}°C";
    }
}

public record ForecastResponse
{
    [JsonPropertyName("current")]
    public CurrentWeather? Current { get; init; }
}

public record CurrentWeather
{
    [JsonPropertyName("temperature_2m")]
    public double Temperature { get; init; }

    [JsonPropertyName("wind_speed_10m")]
    public double WindSpeed { get; init; }
}

